INSERT INTO `articles` (`id_shoes`, `nom`, `categorie`, `marque`, `genre`, `Prix`, `materiaux`, `usage`, `caracteristiques`, `description`, `mots_cles`, `stock_total`, `url_image`) VALUES
(1, 'Nova Air Lifestyle', 'Baskets lifestyle', 'UrbanStep', 'Mixte', '89.99', 'Tige: Mesh respirant; Semelle: EVA; Doublure: Textile recyclé', 'Quotidien,Ville,Loisirs', 'Ultra légères,Respirantes,Semelle amortissante,Usage quotidien,Lacets plats', 'Les Nova Air Lifestyle sont conçues pour offrir un confort optimal au quotidien. Leur tige en mesh respirant assure une excellente circulation de l\'air même lors des longues journées. La semelle en EVA absorbe efficacement les chocs à chaque pas, réduisant la fatigue. Leur design épuré et moderne s\'adapte aussi bien à une tenue décontractée qu\'à un look urbain soigné. Légères et polyvalentes, elles sont idéales pour la ville, les courses et les sorties du week-end.', 'confort,ville,respirant,léger,quotidien,lifestyle,casual,urbain', 1309, 'images/image1.png'),
(2, 'RetroWave 90s', 'Baskets lifestyle', 'UrbanStep', 'Mixte', '99.90', 'Tige: Cuir synthétique; Semelle: Caoutchouc; Doublure: Textile', 'Ville,Loisirs,Mode', 'Style rétro années 90,Semelle épaisse,Confort toute journée,Languette rembourrée', 'Inspirées des icônes des années 90, les RetroWave 90s revivent avec une touche moderne. Leur tige en cuir synthétique vieilli et leur semelle épaisse en caoutchouc rappellent les classiques du streetwear, tout en offrant le confort contemporain. La languette généreusement rembourrée et le col moelleux garantissent un maintien du pied excellent. Un must-have pour les amateurs de mode rétro et de style urbain décalé.', 'rétro,90s,streetwear,mode,lifestyle,vintage,tendance', 1348, 'images/image2.png'),
(3, 'CloudStep Lite', 'Baskets lifestyle', 'UrbanStep', 'Femme', '74.90', 'Tige: Mesh doux; Semelle: Mousse mémoire; Doublure: Microfibre', 'Quotidien,Ville', 'Semelle mémoire de forme,Ultra douce,Légère,Lacets élastiques,Confort intensif', 'Les CloudStep Lite sont pensées pour les femmes qui recherchent avant tout le confort sans sacrifier le style. Leur semelle en mousse mémoire de forme s\'adapte à la morphologie du pied pour un maintien personnalisé. La tige en mesh doux épouse le pied sans contraindre. Les lacets élastiques permettent d\'enfiler et d\'enlever les chaussures sans effort. Parfaites pour de longues journées debout ou pour se déplacer en ville.', 'confort,mousse mémoire,femme,légère,ville,quotidien,doux', 1153, 'images/image3.png'),
(4, 'NeoUrban Street', 'Baskets lifestyle', 'UrbanStep', 'Homme', '109.90', 'Tige: Mesh technique + Overlays synthétiques; Semelle: EVA bi-densité; Doublure: Textile', 'Ville,Mode,Quotidien', 'Look technique urbain,Semelle bi-densité,Amorti renforcé,Languette zippée,Anti-odeur', 'Les NeoUrban Street combinent esthétique technique et confort urbain dans un design masculin assumé. Les overlays en matière synthétique renforcent les zones d\'usure tout en apportant une structure au pied. La semelle bi-densité offre un amorti adapté aux longues marches sur bitume. La languette zippée sur le côté facilite l\'enfilage. Le traitement anti-odeur de la doublure assure une hygiène durable même lors d\'une utilisation intensive.', 'technique,urbain,homme,amorti,quotidien,street,confort', 1282, 'images/image4.png'),
(5, 'AirFlex Pastel', 'Baskets lifestyle', 'FlyMotion', 'Femme', '84.90', 'Tige: Mesh coloré; Semelle: EVA; Doublure: Textile doux', 'Quotidien,Ville,Loisirs', 'Coloris pastel tendance,Légères,Respirantes,Semelle flexible,Style décontracté', 'Les AirFlex Pastel apportent une touche de couleur douce et tendance à votre garde-robe. Disponibles en trois coloris pastel exclusifs, elles combinent légèreté et respirabilité pour un port agréable toute la journée. La semelle flexible en EVA offre un bon retour d\'énergie et absorbe les chocs sur les surfaces dures. Idéales pour les tenues printanières et estivales, elles s\'associent facilement à des robes, jupes ou jeans.', 'pastel,tendance,couleur,légère,femme,printanier,été,lifestyle', 1273, 'images/image5.png'),
(6, 'StreetWave Bold', 'Baskets lifestyle', 'UrbanStep', 'Mixte', '119.00', 'Tige: Cuir synthétique + Mesh; Semelle: Caoutchouc vulcanisé; Doublure: Textile', 'Ville,Mode,Streetwear', 'Design bold statement,Semelle plateforme 3cm,Renforts latéraux,Style oversize', 'Les StreetWave Bold s\'imposent comme une pièce maîtresse de tout outfit streetwear. Leur semelle plateforme de 3cm donne une stature affirmée, tandis que le colorblock audacieux ne laisse personne indifférent. La combinaison cuir synthétique et mesh offre à la fois structure et respirabilité. Les renforts latéraux stabilisent le pied sur les terrains urbains variés. Pour ceux qui veulent se démarquer sans compromis sur le confort.', 'streetwear,plateforme,bold,mode,statement,urbain,tendance,colorblock', 1551, 'images/image6.png'),
(7, 'Velocity Pro X', 'Baskets sport', 'Athletica', 'Mixte', '119.90', 'Tige: Synthétique renforcé; Semelle: Caoutchouc haute résistance; Doublure: Microfibre', 'Sport,Fitness,Salle de sport', 'Stabilité renforcée,Semelle grip multi-surfaces,Maintien latéral,Languette anti-slip,Résistant abrasion', 'Les Velocity Pro X sont conçues pour les sportifs qui ne font aucun compromis sur la performance. La tige en synthétique renforcé offre un maintien latéral exceptionnel lors des changements de direction rapides. La semelle en caoutchouc haute résistance garantit une adhérence optimale sur sols lisses, parquet et béton. La languette anti-slip maintient les lacets en place pendant toute l\'activité. Idéales pour la musculation, le HIIT, le crossfit et les entraînements polyvalents.', 'sport,fitness,salle,crossfit,HIIT,stabilité,performance,grip,musculation', 1746, 'images/image7.png'),
(8, 'FlexRun Training', 'Baskets sport', 'Athletica', 'Mixte', '99.99', 'Tige: Mesh; Semelle: EVA; Doublure: Textile anti-bactérien', 'Fitness,Cardio,Salle de sport', 'Flexibles,Respirantes,Amorti léger,Légères,Grip modéré,Bonne flexibilité', 'Les FlexRun Training sont parfaites pour les séances de fitness polyvalent et de cardio en salle. Leur tige en mesh assure une excellente ventilation pendant les efforts intenses. La semelle souple en EVA offre un amorti léger et une grande flexibilité permettant des mouvements naturels du pied. La doublure anti-bactérienne limite le développement des odeurs. Un excellent rapport qualité-prix pour débuter ou intensifier sa pratique sportive.', 'fitness,cardio,salle,léger,flexible,sport,respirant,entraînement', 1477, 'images/image8.png'),
(9, 'PowerGrip Court', 'Baskets sport', 'Athletica', 'Homme', '129.90', 'Tige: Synthétique; Semelle: Caoutchouc usiné; Doublure: Textile respirant', 'Tennis,Padel,Sports de raquette', 'Semelle usinée pour courts,Renfort orteil,Stabilité latérale,Amorti ciblé talon,Durabililté renforcée', 'Les PowerGrip Court sont spécialement conçues pour les sports de raquette sur tous types de surfaces. La semelle en caoutchouc usinée offre une accroche précise sur terre battue, résine et béton. Le renfort au niveau des orteils protège contre l\'usure liée aux changements de direction fréquents. La stabilité latérale empêche les entorses lors des appuis rapides. Un choix incontournable pour le tennis, le padel et le badminton.', 'tennis,padel,raquette,court,sport,grip,latéral,stabilité,badminton', 1132, 'images/image9.png'),
(10, 'MaxBoost Gym', 'Baskets sport', 'FlyMotion', 'Mixte', '109.00', 'Tige: Mesh renforcé; Semelle: Caoutchouc plat; Doublure: Microfibre', 'Musculation,Crossfit,Sport', 'Semelle plate idéale musculation,Très stable,Faible drop,Renfort talon rigide,Excellent transfert de force', 'Les MaxBoost Gym sont le choix des pratiquants de musculation sérieux. Leur semelle plate en caoutchouc avec un drop minimal favorise un meilleur transfert de force vers le sol lors des squats, soulevés de terre et presses. Le renfort talon rigide assure une stabilité maximale sous les charges lourdes. Légèrement plus rigides que des baskets classiques, elles offrent le maintien nécessaire pour progresser en toute sécurité.', 'musculation,squat,soulevé de terre,crossfit,plat,stable,force,powerlifting', 1668, 'images/image10.png'),
(11, 'AeroBoost React', 'Baskets sport', 'FlyMotion', 'Mixte', '134.90', 'Tige: Mesh technique; Semelle: Mousse réactive; Doublure: Textile', 'Sport,HIIT,Cardio intense', 'Mousse réactive haute énergie,Rebond optimal,Légère,Respirante,Confort intensif', 'Les AeroBoost React exploitent une technologie de mousse réactive haute performance pour maximiser le rebond à chaque foulée. Idéales pour les séances de HIIT intensives, elles absorbent les impacts tout en restituant l\'énergie pour enchaîner les mouvements. La tige en mesh technique assure une ventilation optimale lors des efforts soutenus. Leur légèreté remarquable réduit la fatigue musculaire pendant les longs entraînements.', 'HIIT,réactif,rebond,cardio,sport,légère,énergie,entraînement intensif', 1369, 'images/image11.png'),
(12, 'AeroRun 5 Pro', 'Running', 'FlyMotion', 'Mixte', '139.00', 'Tige: Mesh technique ultra-léger; Semelle: Mousse réactive; Doublure: Textile', 'Running,Course à pied,Route', 'Amorti dynamique,Légèreté extrême,Idéale longues distances,Drop 8mm,Semelle anti-dérapante route', 'Les AeroRun 5 Pro représentent l\'équilibre parfait entre légèreté, amorti et dynamisme pour les coureurs de fond. La mousse réactive de la semelle absorbe efficacement les chocs des longues distances tout en restituant l\'énergie pour maintenir l\'allure. Le mesh ultra-léger de la tige réduit le poids total à seulement 265 grammes. Le drop de 8mm convient à une large majorité de coureurs. Que vous vous prépariez à un 10km ou un marathon, les AeroRun 5 Pro vous accompagnent.', 'running,course,marathon,longue distance,route,léger,amorti,drop 8mm', 1724, 'images/image12.png'),
(13, 'SpeedFlow Race', 'Running', 'FlyMotion', 'Mixte', '159.90', 'Tige: Mesh de course; Semelle: Plaque carbone + Mousse; Doublure: Textile minimal', 'Running,Compétition,Route', 'Plaque carbone propulsive,Poids minimal,Semelle épaisse racing,Drop 4mm,Pour la compétition', 'Les SpeedFlow Race sont les chaussures des coureurs qui visent la performance absolue en compétition. La plaque carbone intégrée dans la semelle crée un effet propulsif unique qui optimise l\'économie de course. La mousse racing ultra-légère et le drop de 4mm favorisent une foulée avant-pied dynamique. Pesant seulement 220 grammes, elles minimisent la fatigue sur les distances de 5km au marathon. Réservées aux coureurs entraînés pour une utilisation en course ou en entraînement rapide.', 'compétition,carbone,racing,marathon,performance,vitesse,propulsion,avant-pied', 1486, 'images/image13.png'),
(14, 'EnduroTrail GTX', 'Running', 'MountainEdge', 'Mixte', '149.90', 'Tige: Mesh renforcé waterproof; Semelle: Lugs trail; Doublure: Gore-Tex', 'Trail,Running montagne,Sentiers', 'Imperméable Gore-Tex,Crampons trail profonds,Protection orteils,Drainage rapide,Accroche terre humide', 'Les EnduroTrail GTX sont conçues pour les traileurs qui affrontent tous les terrains et toutes les météos. La membrane Gore-Tex intégrée maintient les pieds au sec même dans les passages à gué ou sous la pluie battante. Les crampons profonds mordent efficacement dans la boue, les rochers et les feuilles mouillées. La protection renforcée des orteils préserve des chocs sur les terrains chaotiques. Que vous fassiez du trail court ou des ultras, elles tiennent la distance.', 'trail,montagne,sentiers,gore-tex,imperméable,crampons,boue,terrain,ultra', 1572, 'images/image14.png'),
(15, 'FlowLite Daily', 'Running', 'Athletica', 'Mixte', '89.90', 'Tige: Mesh respirant; Semelle: EVA; Doublure: Textile', 'Running,Jogging,Débutant', 'Polyvalente,Confortable,Drop 10mm,Bonne durabilité,Idéale débutant', 'Les FlowLite Daily sont la chaussure de running idéale pour débuter ou courir régulièrement sans se ruiner. Leur semelle en EVA confortable et leur tige respirante offrent tout le nécessaire pour des sorties plaisantes de 5 à 15km. Le drop de 10mm accompagne naturellement la foulée talon des coureurs débutants. Solides et durables, elles résistent aux entraînements répétés sur route et chemin. Un excellent premier choix pour se lancer dans la course à pied.', 'débutant,jogging,running,quotidien,confort,route,accessible,premier', 1661, 'images/image15.png'),
(16, 'UltraStep Boost', 'Running', 'FlyMotion', 'Mixte', '169.00', 'Tige: Mesh 3D knit; Semelle: Boost foam; Doublure: Textile', 'Running,Long distance,Route', 'Technologie Boost,Retour énergie maximal,Confort longue durée,Tige chaussette,Très légère', 'Les UltraStep Boost intègrent une technologie de mousse Boost révolutionnaire qui offre un retour d\'énergie inégalé à chaque foulée. La tige en mesh 3D knit s\'adapte comme une chaussette à la forme exacte du pied pour un maintien sans coutures irritantes. Idéales pour les longues sorties du dimanche ou la préparation marathon, elles maintiennent leur niveau de confort kilomètre après kilomètre. La légèreté de l\'ensemble réduit significativement la fatigue musculaire.', 'boost,énergie,running,marathon,long,confort,knit,chaussette,foulée', 1740, 'images/image16.png'),
(17, 'SpeedMax Light', 'Running', 'Athletica', 'Mixte', '124.90', 'Tige: Mesh ultra-fin; Semelle: Caoutchouc léger; Doublure: Textile minimal', 'Running,Vitesse,Route', 'Ultralégère,Drop 6mm,Favorise avant-pied,Bonne ventilation,Semi-minimaliste', 'Les SpeedMax Light s\'adressent aux coureurs intermédiaires à avancés qui souhaitent gagner en vitesse et travailler leur foulée avant-pied. Leur poids plume (235g) et leur drop de 6mm encouragent naturellement une attaque milieu-avant du pied. La semelle en caoutchouc léger assure une bonne durabilité sans alourdir le pas. Parfaites pour les séances de fractionné, les courses sur route et l\'entraînement à l\'allure.', 'vitesse,léger,avant-pied,fractionné,intermédiaire,drop 6mm,running,allure', 1398, 'images/image17.png'),
(18, 'TrailRock X Pro', 'Randonnée', 'MountainEdge', 'Mixte', '159.99', 'Tige: Cuir nubuck + membrane imperméable; Semelle: Vibram; Doublure: Membrane waterproof', 'Randonnée,Montagne,Multi-jours', 'Imperméables,Semelle Vibram haute adhérence,Protection anti-chocs,Cheville haute,Support plantaire', 'Les TrailRock X Pro sont pensées pour les randonneurs exigeants qui s\'aventurent sur tous les terrains. La tige en cuir nubuck traité imperméable résiste aux pluies, éclaboussures et passages humides. La semelle Vibram offre une adhérence remarquable sur rochers mouillés, pierriers et sentiers glissants. La tige montante protège et soutient la cheville sur les terrains accidentés. Le support plantaire anatomique réduit la fatigue lors des longues journées de marche avec un sac chargé.', 'randonnée,montagne,vibram,imperméable,cheville,multi-jours,cuir,sentier,GR', 1671, 'images/image18.png'),
(19, 'TrekLite Summer', 'Randonnée', 'MountainEdge', 'Mixte', '119.90', 'Tige: Mesh respirant renforcé; Semelle: Caoutchouc trail; Doublure: Textile', 'Randonnée,Basses altitudes,Été', 'Légères pour la rando,Respirantes,Séchage rapide,Semelle trail,Tige basse', 'Les TrekLite Summer sont parfaites pour la randonnée estivale sur chemins et sentiers de moyenne montagne. Leur tige basse en mesh respirant assure une excellente ventilation lors des ascensions par forte chaleur. Le séchage rapide est idéal pour les passages à gué ou les journées humides. La semelle en caoutchouc trail garantit une bonne accroche sur les chemins variés. Légères et polyvalentes, elles conviennent aussi bien à la marche nordique qu\'aux balades en forêt.', 'randonnée,été,légère,basse,respirant,sentier,forêt,journée,nature', 1746, 'images/image19.png'),
(20, 'RockShield Alpine', 'Randonnée', 'MountainEdge', 'Mixte', '189.90', 'Tige: Cuir pleine fleur; Semelle: Vibram Mega Grip; Doublure: Gore-Tex Performance', 'Randonnée,Haute montagne,Bivouac', 'Gore-Tex haute performance,Vibram Mega Grip,Cramponable,Très rigide,Usage technique', 'Les RockShield Alpine sont des chaussures de haute montagne destinées aux randonneurs techniques et alpinistes. La tige en cuir pleine fleur alliée au Gore-Tex Performance assure une imperméabilité et une respirabilité de haut niveau dans les conditions extrêmes. La semelle Vibram Mega Grip offre une adhérence supérieure sur rochers secs ou humides. La rigidité de la semelle permet l\'utilisation de crampons à clips pour les approches glaciaires. Un équipement premium pour les sorties alpines sérieuses.', 'alpine,haute montagne,gore-tex,vibram,crampon,technique,bivouac,alpinisme', 1409, 'images/image20.png'),
(21, 'ForestGrip Walk', 'Randonnée', 'MountainEdge', 'Mixte', '94.90', 'Tige: Synthétique respirant; Semelle: Caoutchouc naturel; Doublure: Textile', 'Randonnée,Forêt,Balades', 'Abordable,Confortable,Accroche forêt,Légère,Idéale randonnées courtes', 'Les ForestGrip Walk sont le point d\'entrée idéal pour découvrir la randonnée. Abordables et polyvalentes, elles offrent toutes les caractéristiques essentielles pour profiter des balades en forêt et des randonnées de journée sur chemins balisés. La semelle en caoutchouc naturel assure une bonne accroche sur les sols forestiers variés. Confortables dès la première sortie sans nécessiter de rodage prolongé, elles conviennent aux familles et aux randonneurs occasionnels.', 'forêt,balades,débutant,confort,abordable,journée,famille,chemin,nature', 1448, 'images/image21.png'),
(22, 'BreezeWalk Liège', 'Sandales', 'SummerFeet', 'Femme', '59.90', 'Tige: Cuir souple; Semelle: Liège naturel; Doublure: Microfibre', 'Quotidien,Ville,Été', 'Semelle liège anatomique,Réglables,Légères,Respirantes,Confort naturel', 'Les BreezeWalk Liège s\'inspirent des meilleures sandales de confort européennes. La semelle en liège naturel s\'adapte progressivement à la forme du pied pour un confort personnalisé unique. Les brides en cuir souple sont entièrement réglables pour s\'adapter à toutes les morphologies. Légères et respirantes, elles sont parfaites pour les longues journées d\'été en ville ou en vacances. Le cuir se patine avec le temps et devient encore plus beau à l\'usage.', 'liège,cuir,sandales,confort,été,ville,vacances,anatomique,femme', 1254, 'images/image22.png'),
(23, 'OceanBreeze Sport', 'Sandales', 'SummerFeet', 'Mixte', '49.90', 'Tige: Textil synthétique séchage rapide; Semelle: Caoutchouc antidérapant; Doublure: EVA', 'Plage,Eau,Sport aquatique', 'Séchage ultra-rapide,Antidérapante sol mouillé,Drainage intégré,Légères,Résistantes eau salée', 'Les OceanBreeze Sport sont conçues pour tous les environnements aquatiques. Le tissu synthétique à séchage ultra-rapide évite l\'inconfort des sandales détrempées. La semelle en caoutchouc antidérapant assure une sécurité maximale sur les rochers mouillés, les bords de piscine et les pontons. Le système de drainage intégré évacue l\'eau immédiatement. Résistantes à l\'eau salée, au sable et au chlore, elles sont le compagnon idéal de toutes les aventures aquatiques.', 'plage,eau,piscine,sport aquatique,séchage rapide,antidérapant,mer,été', 1541, 'images/image23.png'),
(24, 'SummerFlow Comfort', 'Sandales', 'SummerFeet', 'Femme', '39.90', 'Tige: Textile synthétique; Semelle: Mousse EVA; Doublure: Textile', 'Plage,Quotidien,Loisirs', 'Légères,Souples,Idéales plage,Semelle épaisse moelleuse,Économiques', 'Les SummerFlow Comfort sont des sandales simples, légères et abordables pour profiter pleinement de l\'été. La semelle en mousse EVA épaisse et moelleuse absorbe les chocs et offre un confort immédiat sans période d\'adaptation. Idéales pour la plage, les sorties en ville ou simplement pour flâner, elles s\'enfilent et se retirent en un instant. Leur prix accessible en fait le choix parfait pour avoir une paire de sandales de secours ou pour les vacances.', 'plage,été,légère,abordable,mousse,vacances,sandales,confort,simple', 936, 'images/image24.png'),
(25, 'ComfortStep Pro', 'Sandales', 'GentleStep', 'Homme', '69.90', 'Tige: Cuir véritable; Semelle: Caoutchouc; Doublure: Cuir', 'Ville,Quotidien,Randonnée légère', 'Cuir véritable,Robustes,Style masculin,Polyvalentes,Semelle durable', 'Les ComfortStep Pro sont des sandales en cuir véritable pensées pour l\'homme actif. Leur construction robuste en cuir pleine fleur garantit une durabilité exceptionnelle, même avec un port quotidien intensif. Le cuir de la semelle intérieure absorbe la transpiration et régule naturellement la température. Les boucles métalliques solides permettent un réglage précis pour s\'adapter à tous les pieds. Parfaites pour les vacances actives, la ville ou les randonnées légères.', 'cuir,homme,robuste,ville,randonnée légère,qualité,sandales,quotidien', 1203, 'images/image25.png'),
(26, 'UrbanRidge Winter', 'Bottines', 'NordCraft', 'Mixte', '129.00', 'Tige: Cuir; Semelle: Caoutchouc épais; Doublure: Laine mélangée', 'Hiver,Ville,Quotidien', 'Chaudes,Robustes,Antidérapantes,Doublure laine,Imperméabilité basique,Lacets + zip', 'Les UrbanRidge Winter sont pensées pour affronter les hivers rigoureux sans sacrifier le style. La doublure en laine mélangée maintient une chaleur optimale même par températures négatives. La semelle en caoutchouc épais offre une excellente résistance au froid et une bonne antidérapance sur les trottoirs glissants. L\'association lacets et zip latéral permet un enfilage rapide. Le cuir traité offre une résistance basique à l\'humidité pour les temps maussades.', 'hiver,froid,chaud,laine,antidérapant,bottines,cuir,ville,neige', 1679, 'images/image26.png'),
(27, 'CityWalk Chelsea', 'Bottines', 'NordCraft', 'Femme', '109.90', 'Tige: Cuir synthétique; Semelle: Caoutchouc; Doublure: Textile', 'Ville,Bureau,Quotidien', 'Style Chelsea classique,Élastiques latéraux,Talon carré 3cm,Légère,Élégante', 'Les CityWalk Chelsea revisitent le classique intemporel des bottines Chelsea avec une touche contemporaine. Les élastiques latéraux en tissu élastiqué permettent un enfilage aisé tout en assurant un excellent maintien du pied. Le talon carré de 3cm apporte une légère élévation flatteuse sans compromettre la stabilité. Polyvalentes, elles se portent aussi bien avec un jean qu\'avec une jupe ou un tailleur. Un basique élégant pour toute garde-robe féminine.', 'chelsea,bottines,élégant,ville,bureau,femme,talon,intemporel,classique', 1257, 'images/image27.png'),
(28, 'SnowShield Arctic', 'Bottines', 'NordCraft', 'Mixte', '149.90', 'Tige: Nylon imperméable; Semelle: Caoutchouc froid; Doublure: Polaire Thinsulate 200g', 'Grand froid,Neige,Hiver extrême', 'Imperméables 100%,Isolation Thinsulate 200g,Températures jusqu\'à -25°C,Crampon neige amovible,Fermeture velcro', 'Les SnowShield Arctic sont conçues pour les conditions hivernales les plus sévères. L\'isolation Thinsulate 200g garantit une chaleur optimale jusqu\'à -25°C sans alourdir excessivement la chaussure. La tige en nylon imperméable et la semelle résistante au froid empêchent tout durcissement par basses températures. Le crampon neige amovible fourni avec les chaussures offre une traction supplémentaire sur verglas. La fermeture velcro facilite l\'enfilage avec des gants.', 'neige,grand froid,hiver,thinsulate,imperméable,arctique,verglas,-25°C', 1597, 'images/image28.png'),
(29, 'SoftWalk Classic', 'Mocassins', 'GentleStep', 'Homme', '79.90', 'Tige: Cuir souple; Semelle: Caoutchouc; Doublure: Cuir souple', 'Bureau,Ville,Quotidien', 'Souples,Confortables,Style classique,Pas de lacets,Élégants discrets', 'Les SoftWalk Classic sont des mocassins légers et confortables qui s\'adaptent aussi bien au bureau qu\'aux sorties en ville. Fabriqués en cuir souple pleine fleur, ils épousent naturellement la forme du pied au fil du temps pour un confort personnalisé. L\'absence de lacets permet de les enfiler et les retirer en quelques secondes. La doublure en cuir absorbe la transpiration et garantit une hygiène durable. Un classique masculin indémodable.', 'mocassins,bureau,travail,cuir,confort,homme,classique,sans lacets,élégant', 1609, 'images/image29.png'),
(30, 'UrbanSoft Loafer', 'Mocassins', 'GentleStep', 'Femme', '69.90', 'Tige: Cuir synthétique doux; Semelle: Crêpe; Doublure: Microfibre', 'Bureau,Ville,Quotidien', 'Légère,Féminine,Semelle crêpe douce,Talon plat,Polyvalente', 'Les UrbanSoft Loafer revisitent le mocassin féminin avec une touche de légèreté et de modernité. Le cuir synthétique doux offre l\'esthétique du cuir sans les contraintes d\'entretien. La semelle crêpe ultra-souple amorti chaque pas pour un confort remarquable sur les journées chargées. À talon plat, elles assurent une posture naturelle et réduisent la fatigue. Elles s\'associent élégamment avec des pantalons, jupes ou robes mi-longues.', 'mocassins,femme,plat,bureau,léger,élégant,quotidien,confort,polyvalent', 1032, 'images/image30.png'),
(31, 'ClassicFit Premium', 'Mocassins', 'GentleStep', 'Homme', '119.00', 'Tige: Cuir véritable Nappa; Semelle: Cuir; Doublure: Cuir Nappa', 'Bureau,Soirée,Élégant', 'Cuir Nappa premium,Semelle cuir,Finitions soignées,Très élégants,Fait main Portugal', 'Les ClassicFit Premium représentent l\'excellence artisanale au service du style masculin. Confectionnés à la main au Portugal, ils utilisent uniquement du cuir Nappa de première qualité, connu pour sa douceur incomparable et sa durabilité. La semelle en cuir véritable est interchangeable et peut être ressemblée, assurant une longévité exceptionnelle. Leurs finitions soignées, le point sellier apparent et le lustre naturel du Nappa en font des chaussures de cérémonie autant que des compagnons de bureau élèves.', 'premium,nappa,cuir,artisan,portugal,élégant,bureau,soirée,luxe,qualité', 1473, 'images/image31.png'),
(32, 'Élégance Haute Nuit', 'Talons', 'BelleMode', 'Femme', '89.90', 'Tige: Simili cuir satiné; Semelle: Synthétique; Doublure: Textile', 'Soirée,Fête,Événement', 'Talon aiguille 9cm,Bout pointu,Élégantes,Bride cheville,Semelle anti-dérapante', 'Les Élégance Haute Nuit sont la chaussure de soirée par excellence pour les occasions qui méritent d\'être à la hauteur. Le talon aiguille de 9cm et le bout pointu créent une silhouette élancée et sophistiquée. La bride de cheville fine et ajustable assure le maintien du pied tout au long de la nuit. La semelle antidérapante apportée en embout métal offre une sécurité accrue sur les parquets lisses. Disponibles en noir sobre, rouge passion ou or festif pour toutes les tenues.', 'soirée,talons aiguilles,élégant,fête,gala,9cm,femme,glamour,bride', 939, 'images/image32.png'),
(33, 'SoftHeel Block', 'Talons', 'BelleMode', 'Femme', '79.90', 'Tige: Cuir synthétique; Semelle: Caoutchouc; Doublure: Microfibre', 'Bureau,Ville,Quotidien', 'Talon bloc 5cm,Stable,Confort bureau,Embout carré,Polyvalentes', 'Les SoftHeel Block combinent l\'élégance d\'un talon et le confort d\'une chaussure plate. Le talon bloc de 5cm offre une belle hauteur tout en garantissant une stabilité que les talons aiguilles ne peuvent égaler. L\'embout carré apporte une modernité dans la ligne de la chaussure très tendance. La semelle en caoutchouc assure un bon amorti sur les sols durs des bureaux et trottoirs. Idéales pour les femmes qui veulent rester à l\'aise sans renoncer à la féminité.', 'talon bloc,bureau,stable,confort,5cm,quotidien,carré,femme,tendance', 1169, 'images/image33.png'),
(34, 'NightElegance Stiletto', 'Talons', 'BelleMode', 'Femme', '109.00', 'Tige: Satin; Semelle: Synthétique; Doublure: Textile satin', 'Soirée,Gala,Mariage', 'Talon 10cm,Ornementation cristaux,Très élégantes,Bout amande,Fermeture bride', 'Les NightElegance Stiletto sont créées pour les moments d\'exception qui méritent une chaussure d\'exception. Le satin luxueux de la tige capte la lumière avec élégance, sublimé par une ornementation en cristaux sur la bride. Le talon de 10cm et le bout amande allongent visuellement la jambe pour une silhouette somptueuse. Disponibles dans des teintes métallisées précieuses, elles subliment les robes de soirée, les tenues de mariage ou de cocktail.', 'mariage,gala,soirée,satin,cristaux,10cm,stiletto,luxe,précieux,femme', 1080, 'images/image34.png'),
(35, 'SafeGrip S3 Pro', 'Sécurité', 'WorkGuard', 'Mixte', '109.90', 'Tige: Cuir nubuck; Semelle: Caoutchouc polyuréthane; Doublure: Textile respirant', 'Chantier,Industrie,BTP', 'Norme S3,Embout acier,Anti-perforation,Antistatique,Hydrofuge,Résistant carburants', 'Les SafeGrip S3 Pro répondent à la norme de sécurité la plus stricte du marché, la norme EN ISO 20345 S3. L\'embout en acier résiste à un impact de 200 joules pour une protection maximale des orteils. La semelle anti-perforation protège contre les clous et objets acérés. Les propriétés antistatiques évitent les décharges électrostatiques sur les sites sensibles. Traitées hydrofuges et résistantes aux carburants, elles s\'adaptent à tous les environnements industriels et de chantier.', 'sécurité,S3,chantier,industrie,acier,anti-perforation,norme,BTP,travail', 1063, 'images/image35.png'),
(36, 'SteelPro Light S1P', 'Sécurité', 'WorkGuard', 'Mixte', '79.90', 'Tige: Mesh renforcé; Semelle: EVA + Caoutchouc; Doublure: Textile anti-bactérien', 'Entrepôt,Logistique,Industrie légère', 'Norme S1P,Embout composite léger,Anti-perforation,Légère,Confortable,Anti-bactérien', 'Les SteelPro Light S1P prouvent que sécurité et confort ne sont pas incompatibles. Conformes à la norme S1P, elles intègrent un embout en composite léger (30% plus léger que l\'acier) sans sacrifier la protection contre les impacts de 200 joules. La semelle anti-perforation protège sans rigidifier. Légères et respirantes grâce à leur tige en mesh renforcé, elles réduisent considérablement la fatigue lors des longues journées en entrepôt ou en logistique. La doublure anti-bactérienne combat les odeurs.', 'sécurité,S1P,composite,léger,entrepôt,logistique,confort,anti-bactérien', 1070, 'images/image36.png'),
(37, 'HardWork ESD S2', 'Sécurité', 'WorkGuard', 'Mixte', '129.90', 'Tige: Cuir; Semelle: Spéciale ESD; Doublure: Tissu conducteur', 'Électronique,Laboratoire,Environnements ESD', 'Norme ESD,Dissipation électrostatique certifiée,Embout composite,Antistatique total,Laboratoire', 'Les HardWork ESD S2 sont spécialement conçues pour les environnements où la maîtrise des décharges électrostatiques est critique : électronique, microélectronique, pharmaceutique et laboratoires sensibles. La semelle ESD certifiée et la doublure en tissu conducteur forment un système complet de dissipation des charges statiques répondant à la norme EN 61340-5-1. L\'embout en composite protège les orteils sans interférer avec les propriétés électriques. Idéales pour les salles blanches et environnements ISO.', 'ESD,antistatique,électronique,laboratoire,salle blanche,statique,sécurité,S2', 711, 'images/image37.png'),
(38, 'PureStep Vegan', 'Vegan', 'EcoFeet', 'Mixte', '84.90', 'Tige: Cuir pomme biobased; Semelle: Caoutchouc naturel; Doublure: Microfibre recyclée', 'Quotidien,Ville,Éco-responsable', '100% vegan,Cuir pomme certifié,Matériaux recyclés,Fabrication éthique,Empreinte carbone réduite', 'Les PureStep Vegan représentent l\'avant-garde de la chaussure éco-responsable. La tige est fabriquée à partir de cuir de pomme, un matériau innovant issu des déchets de l\'industrie alimentaire italienne offrant texture et résistance similaires au cuir animal. La doublure en microfibre recyclée (issue de bouteilles plastiques récupérées) et la semelle en caoutchouc naturel complètent un cycle de production éthique et certifié. Zéro compromis sur le style ou le confort.', 'vegan,écologique,cuir pomme,recyclé,éthique,durable,zéro déchet,bio,responsable', 1511, 'images/image38.png'),
(39, 'GreenWalk Knit', 'Vegan', 'EcoFeet', 'Mixte', '94.90', 'Tige: Tricot en coton bio recyclé; Semelle: Liège + caoutchouc naturel; Doublure: Lin', 'Quotidien,Ville,Loisirs', 'Tricot bio respirant,Semelle liège naturel,Sans colle animale,Teintures naturelles,Confort naturel', 'Les GreenWalk Knit poussent l\'engagement écologique encore plus loin avec une tige entièrement tricotée en coton biologique recyclé. Les teintures naturelles utilisées évitent les produits chimiques nocifs et respectent les normes les plus strictes de l\'industrie textile. La semelle combinant liège naturel et caoutchouc végétal offre un amorti naturel qui s\'adapte au pied. Aucune colle d\'origine animale n\'entre dans leur fabrication. Une chaussure qui vous permet de marcher léger sur la planète.', 'vegan,bio,coton,liège,naturel,zéro animal,teinture naturelle,écologie,durable', 1759, 'images/image39.png'),
(40, 'SoftHome Cozy', 'Indoor', 'HomeStep', 'Mixte', '34.90', 'Tige: Polaire sherpa; Semelle: Antidérapante mousse; Doublure: Sherpa', 'Maison,Intérieur,Détente', 'Ultra douces,Antidérapantes,Légères,Chaudes,Lavables machine', 'Les SoftHome Cozy sont les pantoufles dont vous ne pourrez plus vous passer. Le sherpa moelleux enveloppe les pieds d\'une chaleur douce et réconfortante, idéale pour les soirées d\'hiver ou les matinées paresseuses. La semelle antidérapante garantit votre sécurité sur les parquets et carrelages. Leur légèreté extrême fait oublier qu\'on les porte. Un vrai plus : elles sont entièrement lavables en machine pour rester fraîches et propres.', 'pantoufles,maison,intérieur,chaud,sherpa,confort,détente,hiver,lavable', 1637, 'images/image40.png'),
(41, 'CozyWarm Memory', 'Indoor', 'HomeStep', 'Femme', '44.90', 'Tige: Velours côtelé; Semelle: Mousse mémoire + antidérapant; Doublure: Microfibre', 'Maison,Détente,Confort', 'Semelle mémoire personnalisée,Velours luxueux,Ouverture facile,Légère,Confort supérieur', 'Les CozyWarm Memory sont des chaussons pour femmes qui allient confort supérieur et esthétique raffinée. La semelle en mousse mémoire s\'adapte avec précision à la morphologie du pied pour un soutien personnalisé qui prévient la fatigue plantaire. Le velours côtelé de la tige est doux au toucher et conserve bien la chaleur. L\'ouverture large facilite l\'enfilage même à la sortie du lit. Un cadeau idéal ou un plaisir que l\'on s\'offre à soi-même.', 'chaussons,maison,femme,mousse mémoire,velours,confort,détente,cadeau,doux', 1324, 'images/image41.png'),
(42, 'WalkPro Comfort', 'Marche', 'GentleStep', 'Mixte', '89.90', 'Tige: Cuir + mesh; Semelle: EVA renforcée; Doublure: Gel anatomique', 'Marche,Ville,Quotidien,Senior', 'Support plantaire gel,Large embout,Confort longue durée,Antidérapante,Facile à enfiler', 'Les WalkPro Comfort sont conçues pour les marcheurs qui privilégient le confort avant tout. Le support plantaire en gel anatomique répartit uniformément les pressions sous le pied, réduisant douleurs et fatigue même lors de très longues marches. L\'embout large offre la place nécessaire aux orteils sans pincement. La semelle EVA renforcée amorti efficacement sur tous les revêtements urbains. L\'ouverture large et le système de lacets à enroulement facilitent l\'enfilage pour les personnes à mobilité réduite.', 'marche,confort,gel,podologie,senior,large,antidérapant,quotidien,orthopédique', 1581, 'images/image42.png'),
(43, 'TrailWalk Nature', 'Marche', 'MountainEdge', 'Mixte', '74.90', 'Tige: Synthétique respirant; Semelle: Caoutchouc trail; Doublure: Textile', 'Marche,Nature,Campagne', 'Polyvalente,Légère,Accroche terrain mixte,Confortable,Bon rapport qualité-prix', 'Les TrailWalk Nature sont la chaussure de marche polyvalente par excellence pour ceux qui aiment alterner chemins de campagne et rues pavées. La semelle en caoutchouc trail offre une bonne accroche sur les sols variés : herbe humide, chemins de terre, pierres et asphalte. Légères et confortables dès le premier port, elles conviennent aussi bien aux promenades du dimanche qu\'aux marches de plusieurs heures. Un excellent rapport qualité-prix pour débuter la marche nature.', 'marche,nature,campagne,polyvalent,léger,terrain mixte,promenade,famille', 1716, 'images/image43.png'),
(44, 'BareStep Zero Drop', 'Minimalistes', 'FreeMotion', 'Mixte', '99.90', 'Tige: Mesh ultra-fin; Semelle: 4mm caoutchouc naturel; Doublure: Aucune (minimal)', 'Running,Marche,Minimalisme', 'Drop 0mm,Semelle 4mm,Très flexible,Léger (150g),Renforcement pied naturel', 'Les BareStep Zero Drop sont la référence pour les adeptes du mouvement minimaliste. Le drop zéro place talon et avant-pied à la même hauteur, favorisant une posture naturelle et un renforcement progressif de toute la chaîne musculaire du pied et de la jambe. La semelle de 4mm en caoutchouc naturel offre une protection minimale tout en permettant une perception fine du sol. Avec seulement 150 grammes, elles disparaissent sous le pied. Idéales pour la transition minimaliste, à adopter progressivement.', 'minimaliste,zéro drop,barefoot,pieds nus,naturel,léger,running,transition,renforcement', 2127, 'images/image44.png'),
(45, 'NatureFlex Wide', 'Minimalistes', 'FreeMotion', 'Mixte', '119.90', 'Tige: Mesh 3D respirant; Semelle: 6mm caoutchouc; Doublure: Lin naturel', 'Quotidien,Marche,Minimalisme', 'Embout large (wide),Drop 0mm,Tige très flexible,6mm protection,Quotidien minimaliste', 'Les NatureFlex Wide combinent les bénéfices du minimalisme avec un embout extra-large qui laisse les orteils libres de s\'étaler naturellement. L\'embout wide est particulièrement recommandé pour les personnes ayant des orteils en éventail, des oignons ou simplement préférant un espace généreux. La tige en mesh 3D offre une ventilation optimale pour les longues journées. La semelle de 6mm offre une protection légèrement supérieure au BareStep, idéale pour commencer la transition minimaliste en douceur.', 'minimaliste,wide,large,orteils,drop zéro,quotidien,transition,oignons,nature', 2095, 'images/image45.png'),
(46, 'EasyStep Canvas', 'Slip-on', 'DailyWear', 'Mixte', '44.90', 'Tige: Toile canvas; Semelle: Vulcanisée caoutchouc; Doublure: Textile', 'Quotidien,Détendu,Été', 'Sans lacets,Élastiques latéraux,Style canvas classique,Légère,Lavable', 'Les EasyStep Canvas revisitent la chaussure canvas de toile classique en version slip-on sans lacets. Les élastiques latéraux discrets permettent d\'enfiler et d\'enlever les chaussures sans effort. La semelle vulcanisée en caoutchouc assure une bonne durabilité et une adhérence suffisante pour le quotidien. Légères et respirantes en toile, elles sont parfaites pour l\'été, la plage ou le quotidien décontracté. Passent en machine à 30°C pour un entretien facile.', 'slip-on,canvas,sans lacets,toile,décontracté,été,rapide,facile,lavable', 1952, 'images/image46.png'),
(47, 'StreetFlex Knit', 'Slip-on', 'UrbanStep', 'Mixte', '64.90', 'Tige: Tricot knit; Semelle: EVA; Doublure: Textile', 'Quotidien,Ville,Bureau décontracté', 'Tige chaussette tricot,Sans lacets,Légère,Respirante,Style moderne', 'Les StreetFlex Knit exploitent la technologie du tricot chaussette pour créer un slip-on d\'une légèreté et d\'un confort inégalés. La tige en tricot knit s\'adapte comme une seconde peau aux contours du pied, sans coutures irritantes. L\'élasticité naturelle du tricot facilite l\'enfilage et le retrait. La semelle EVA légère assure confort et amorti pour les journées actives. Un choix moderne et pratique pour le quotidien urbain ou le bureau casual.', 'slip-on,knit,tricot,sans lacets,moderne,léger,bureau,casual,chaussette', 1644, 'images/image47.png'),
(48, 'RainStep WP', 'Imperméables', 'DryWalk', 'Mixte', '99.90', 'Tige: Cuir synthétique waterproof; Semelle: Caoutchouc; Doublure: Membrane imperméable', 'Pluie,Ville,Quotidien', 'Imperméables garanties,Style baskets,Membrane étanche,Respirante,Semelle antidérapante pluie', 'Les RainStep WP prouvent qu\'une chaussure imperméable peut être élégante et discrète. Leur aspect de baskets classiques ne trahit pas leur imperméabilité totale garantie par la membrane waterproof intégrée. La tige en cuir synthétique traité repousse l\'eau dès le premier contact. La semelle en caoutchouc avec rainures profondes assure une adhérence sécurisée sur les trottoirs mouillés. Respirantes malgré leur imperméabilité, elles évitent l\'effet de botte chaude.', 'imperméable,pluie,waterproof,étanche,antidérapant,ville,respirant,pluie', 2021, 'images/image48.png'),
(49, 'StormGuard Boot', 'Imperméables', 'DryWalk', 'Mixte', '129.90', 'Tige: Caoutchouc naturel; Semelle: Caoutchouc cramponnée; Doublure: Néoprène', 'Pluie intense,Boue,Outdoor', '100% étanche,Isolation néoprène,Crampons boue,Tige haute 20cm,Résistant milieux extrêmes', 'Les StormGuard Boot sont les bottes tout-terrain pour ceux qui n\'ont pas peur des éléments. La tige en caoutchouc naturel de 20cm de hauteur offre une étanchéité absolue même dans les flaques profondes. La doublure en néoprène maintient les pieds chauds dans l\'eau froide jusqu\'à environ 5°C. Les crampons profonds de la semelle mordent efficacement dans la boue épaisse et les terrains détrempés. Idéales pour la chasse, la pêche, le jardinage ou les festivals pluvieux.', 'bottes,étanche,boue,pluie,caoutchouc,néoprène,festival,chasse,outdoor,terrain', 1811, 'images/image49.png'),
(50, 'PowerTrain Cross', 'Training', 'ActiveFeet', 'Mixte', '89.90', 'Tige: Mesh synthétique; Semelle: Caoutchouc pivot; Doublure: Textile respirant', 'Cross-training,Salle,Polyvalent', 'Zone pivot pour rotations,Bonne stabilité,Polyvalente,Soutien latéral,Légère', 'Les PowerTrain Cross sont la chaussure de cross-training polyvalente qui accompagne tous vos entraînements. La zone pivot sous l\'avant-pied facilite les rotations lors des mouvements de danse ou des exercices dynamiques. Le soutien latéral prévient les entorses lors des déplacements rapides. La semelle en caoutchouc offre une adhérence adaptée aussi bien aux parquets de salle qu\'aux sols sportifs. Légères et respirantes, elles conviennent au HIIT, au cross-training, à l\'aérobic et au Zumba.', 'cross-training,polyvalent,salle,rotation,HIIT,zumba,aérobic,stable,fitness', 1807, 'images/image50.png'),
(51, 'FlexDance Studio', 'Danse', 'MoveArt', 'Femme', '69.90', 'Tige: Toile de danse; Semelle: Daim naturel + caoutchouc avant-pied; Doublure: Textile', 'Danse,Ballet jazz,Modern jazz', 'Semelle daim technique,Split sole,Légèreté maximale,Flexibilité totale,Respirante', 'Les FlexDance Studio sont conçues pour les danseuses pratiquant le ballet jazz et le modern jazz. La semelle split en daim naturel (avant-pied et talon séparés) offre une flexibilité maximale du pied tout en assurant l\'adhérence nécessaire sur les parquets de danse. La toile de danse légère épouse parfaitement le pied pour une proprioception optimale. L\'avant-pied en caoutchouc offre une durabilité supplémentaire aux zones de forte usure. Une chaussure technique pour danseuses exigeantes.', 'danse,ballet jazz,modern,split sole,daim,flexible,studio,technique,danseuse', 1226, 'images/image51.png'),
(52, 'StudioPro Latin', 'Danse', 'MoveArt', 'Femme', '89.90', 'Tige: Satin; Semelle: Daim; Doublure: Cuir souple', 'Danse latine,Salsa,Bachata', 'Talon cubain 5cm,Bride cheville,Semelle daim,Confort danse,Fermeture boucle', 'Les StudioPro Latin sont spécialement développées pour les danseuses de salsa, bachata, merengue et danses latines. Le talon cubain de 5cm offre la hauteur et la stabilité caractéristiques de ces danses, permettant d\'exécuter virages et déplacements avec précision. La semelle en daim offre le niveau de glisse idéal sur les parquets sans risque de dérapage. La bride de cheville réglable maintient le pied fermement dans la chaussure pendant les tours. Conçues pour des heures de pratique sans douleur.', 'danse latine,salsa,bachata,talon cubain,daim,studio,soirée,glisse,femme', 1459, 'images/image52.png'),
(53, 'SummerSoft Classic', 'Espadrilles', 'Mediterraneo', 'Mixte', '34.90', 'Tige: Toile de jute; Semelle: Jute naturel; Doublure: Textile', 'Été,Plage,Vacances', '100% jute naturel,Légères,Respirantes,Style méditerranéen,Artisanal', 'Les SummerSoft Classic perpétuent la tradition centenaire de l\'espadrille artisanale méditerranéenne. La tige et la semelle en jute naturel offrent une respirabilité inégalée, idéale pour les journées chaudes d\'été. Légères comme une plume, elles disparaissent au pied pour un confort naturel. Fabriquées selon des méthodes artisanales transmises de génération en génération dans les ateliers du Pays Basque, chaque paire est unique. Parfaites pour la terrasse, les vacances ou simplement profiter du soleil.', 'espadrilles,jute,artisanal,été,méditerranée,naturel,légère,plage,vacances', 1777, 'images/image53.png'),
(54, 'CoastLine Wedge', 'Espadrilles', 'Mediterraneo', 'Femme', '54.90', 'Tige: Toile coton; Semelle compensée: Jute + EVA; Doublure: Textile', 'Été,Ville,Soirée décontractée', 'Compensées 6cm,Légères,Lacets montants,Tendance,Style côtier', 'Les CoastLine Wedge subliment l\'espadrille classique avec une semelle compensée de 6cm qui apporte élégance et stature. La plateforme en jute naturel recouvert d\'EVA allie le style traditionnel à un confort moderne longue durée. Les lacets en coton qui s\'enroulent autour de la cheville apportent une touche romantique et assurent le maintien du pied. Parfaites pour dîner en terrasse, une soirée entre amis ou se promener dans les ruelles d\'un village de vacances.', 'espadrilles compensées,été,femme,talon,ville,côtier,vacances,tendance,lacets', 1242, 'images/image54.png'),
(55, 'ComfortClog Pro', 'Sabots', 'HomeStep', 'Mixte', '49.90', 'Tige: EVA antibactérien; Semelle: EVA; Doublure: Aucune', 'Médical,Cuisine,Usage professionnel', 'Antibactérien,Facile à nettoyer,Antidérapant,Aérations latérales,Réglable arrière,Poids léger', 'Les ComfortClog Pro sont les sabots de référence pour les professionnels de santé, de la restauration et des milieux techniques. La matière EVA antibactérienne empêche la prolifération des bactéries et des champignons. Le nettoyage est instantané : une simple passée à l\'eau froide suffit. La bride arrière réglable assure un maintien sécurisé lors des déplacements rapides. Les aérations latérales permettent une circulation d\'air continue. Antidérapants sur sols mouillés, ils répondent aux normes professionnelles.', 'sabots,médical,cuisine,professionnel,antibactérien,infirmier,restauration,antidérapant', 2827, 'images/image55.png'),
(56, 'GardenStep Outdoor', 'Sabots', 'HomeStep', 'Mixte', '29.90', 'Tige: EVA recyclé; Semelle: EVA; Doublure: Aucune', 'Jardinage,Extérieur,Plage', 'Prix mini,Léger,Facile à laver,Ventilation maximale,Séchage instantané', 'Les GardenStep Outdoor sont les sabots utilitaires parfaits pour toutes les activités extérieures. Fabriqués en EVA recyclé, ils ont une empreinte écologique réduite. Leur prix mini en fait un investissement sans risque pour le jardinage, la plage, les activités nautiques ou simplement pour ne pas salir ses bonnes chaussures. Les aérations généreuses assurent une ventilation maximale et un séchage quasi instantané après l\'eau. Extrêmement légers et faciles à nettoyer au tuyau d\'arrosage.', 'jardinage,plage,eau,léger,économique,EVA recyclé,extérieur,pratique,facile', 2859, 'images/image56.png'),
(57, 'LightHiker Mid', 'Montantes légères', 'MountainEdge', 'Mixte', '109.90', 'Tige: Mesh + cuir synthétique; Semelle: Caoutchouc trail; Doublure: Textile', 'Randonnée,Trail court,Camping', 'Tige mi-haute,Légère,Protection cheville modérée,Séchage rapide,Polyvalente', 'Les LightHiker Mid occupent la niche entre la chaussure basse et la bottine haute de randonnée. Leur tige mi-haute offre une protection et un maintien de la cheville supérieurs à une chaussure basse, sans la rigidité ni le poids d\'une chaussure technique de montagne. Le mix mesh respirant et cuir synthétique assure légèreté et durabilité. Leur séchage rapide est apprécié lors des randonnées comportant des passages humides. Idéales pour les randonnées journée avec dénivelé modéré.', 'montante,mi-haute,randonnée,cheville,légère,trail court,polyvalente,camping', 1817, 'images/image57.png'),
(58, 'CityHigh Urban', 'Montantes légères', 'UrbanStep', 'Mixte', '119.00', 'Tige: Canvas épais + cuir; Semelle: Caoutchouc; Doublure: Textile', 'Ville,Hiver,Style', 'Tige haute style,Lacets à crochets,Chaudes sans doublure lourde,Semelle robuste,Look streetwear', 'Les CityHigh Urban revisitent la sneaker montante dans un esprit streetwear contemporain. La tige haute en canvas épais renforcé de cuir offre un maintien de cheville confortable et un style affirmé. Le système de laçage à crochets métalliques vintage est à la fois fonctionnel et esthétique. La semelle en caoutchouc robuste assure une longévité supérieure sur les sols urbains. Assez chaudes pour les intersaisons et l\'hiver doux sans être étouffantes.', 'montante,urban,streetwear,lacets,hiver,ville,canvas,style,cheville', 1450, 'images/image58.png');
